    "code": "/* eslint-disable react/no-unknown-property */\nimport { Canvas, useFrame, useThree } from '@react-three/fiber';\nimport { forwardRef, useRef, useMemo, useLayoutEffect } from 'react';\nimport { Color } from 'three';\n\nconst hexToNormalizedRGB = hex => {\n  hex = hex.replace('#', '');\n  return [\n    parseInt(hex.slice(0, 2), 16) / 255,\n    parseInt(hex.slice(2, 4), 16) / 255,\n    parseInt(hex.slice(4, 6), 16) / 255\n  ];\n};\n\nconst vertexShader = `\nvarying vec2 vUv;\nvarying vec3 vPosition;\n\nvoid main() {\n  vPosition = position;\n  vUv = uv;\n  gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);\n}\n`;\n\nconst fragmentShader = `\nvarying vec2 vUv;\nvarying vec3 vPosition;\n\nuniform float uTime;\nuniform vec3  uColor;\nuniform float uSpeed;\nuniform float uScale;\nuniform float uRotation;\nuniform float uNoiseIntensity;\n\nconst float e = 2.71828182845904523536;\n\nfloat noise(vec2 texCoord) {\n  float G = e;\n  vec2  r = (G * sin(G * texCoord));\n  return fract(r.x * r.y * (1.0 + texCoord.x));\n}\n\nvec2 rotateUvs(vec2 uv, float angle) {\n  float c = cos(angle);\n  float s = sin(angle);\n  mat2  rot = mat2(c, -s, s, c);\n  return rot * uv;\n}\n\nvoid main() {\n  float rnd        = noise(gl_FragCoord.xy);\n  vec2  uv         = rotateUvs(vUv * uScale, uRotation);\n  vec2  tex        = uv * uScale;\n  float tOffset    = uSpeed * uTime;\n\n  tex.y += 0.03 * sin(8.0 * tex.x - tOffset);\n\n  float pattern = 0.6 +\n                  0.4 * sin(5.0 * (tex.x + tex.y +\n                                   cos(3.0 * tex.x + 5.0 * tex.y) +\n                                   0.02 * tOffset) +\n                           sin(20.0 * (tex.x + tex.y - 0.1 * tOffset)));\n\n  vec4 col = vec4(uColor, 1.0) * vec4(pattern) - rnd / 15.0 * uNoiseIntensity;\n  col.a = 1.0;\n  gl_FragColor = col;\n}\n`;\n\nconst SilkPlane = forwardRef(function SilkPlane({ uniforms }, ref) {\n  const { viewport } = useThree();\n\n  useLayoutEffect(() => {\n    if (ref.current) {\n      ref.current.scale.set(viewport.width, viewport.height, 1);\n    }\n  }, [ref, viewport]);\n\n  useFrame((_, delta) => {\n    ref.current.material.uniforms.uTime.value += 0.1 * delta;\n  });\n\n  return (\n    <mesh ref={ref}>\n      <planeGeometry args={[1, 1, 1, 1]} />\n      <shaderMaterial uniforms={uniforms} vertexShader={vertexShader} fragmentShader={fragmentShader} />\n    </mesh>\n  );\n});\nSilkPlane.displayName = 'SilkPlane';\n\nconst Silk = ({ speed = 5, scale = 1, color = '#7B7481', noiseIntensity = 1.5, rotation = 0 }) => {\n  const meshRef = useRef();\n\n  const uniforms = useMemo(\n    () => ({\n      uSpeed: { value: speed },\n      uScale: { value: scale },\n      uNoiseIntensity: { value: noiseIntensity },\n      uColor: { value: new Color(...hexToNormalizedRGB(color)) },\n      uRotation: { value: rotation },\n      uTime: { value: 0 }\n    }),\n    [speed, scale, noiseIntensity, color, rotation]\n  );\n\n  return (\n    <Canvas dpr={[1, 2]} frameloop=\"always\">\n      <SilkPlane ref={meshRef} uniforms={uniforms} />\n    </Canvas>\n  );\n};\n\nexport default Silk;\n",
    "previewCode": "<canvas id=\"rb-silk-gl-prv\" style=\"width:100%;height:100%;background:#000;display:block;\"></canvas>\n<script>\n(function(){\n  var c = document.getElementById('rb-silk-gl-prv');\n  var gl = c.getContext('webgl2');\n  if(!gl) {\n    c.style.background = '#000000';\n    return;\n  }\n\n  var vs = `#version 300 es\n  in vec2 pos;\n  out vec2 vUv;\n  out vec3 vPosition;\n  void main() {\n    vUv = pos * 0.5 + 0.5;\n    vPosition = vec3(pos, 0.0);\n    gl_Position = vec4(pos, 0.0, 1.0);\n  }`;\n\n  var fs = `#version 300 es\n  precision lowp float;\n  in vec2 vUv;\n  in vec3 vPosition;\n  uniform float uTime;\n  uniform vec3  uColor;\n  uniform float uSpeed;\n  uniform float uScale;\n  uniform float uRotation;\n  uniform float uNoiseIntensity;\n  out vec4 fragColor;\n\n  const float e = 2.71828182845904523536;\n\n  float noise(vec2 texCoord) {\n    float G = e;\n    vec2  r = (G * sin(G * texCoord));\n    return fract(r.x * r.y * (1.0 + texCoord.x));\n  }\n\n  vec2 rotateUvs(vec2 uv, float angle) {\n    float c = cos(angle);\n    float s = sin(angle);\n    mat2  rot = mat2(c, -s, s, c);\n    return rot * uv;\n  }\n\n  void main() {\n    float rnd        = noise(gl_FragCoord.xy);\n    vec2  uv         = rotateUvs(vUv * uScale, uRotation);\n    vec2  tex        = uv * uScale;\n    float tOffset    = uSpeed * uTime;\n\n    tex.y += 0.03 * sin(8.0 * tex.x - tOffset);\n\n    float pattern = 0.6 +\n                    0.4 * sin(5.0 * (tex.x + tex.y +\n                                     cos(3.0 * tex.x + 5.0 * tex.y) +\n                                     0.02 * tOffset) +\n                             sin(20.0 * (tex.x + tex.y - 0.1 * tOffset)));\n\n    vec4 col = vec4(uColor, 1.0) * vec4(pattern) - rnd / 15.0 * uNoiseIntensity;\n    col.a = 1.0;\n    fragColor = col;\n  }`;\n\n  function createShader(gl, type, source) {\n    var shader = gl.createShader(type);\n    gl.shaderSource(shader, source);\n    gl.compileShader(shader);\n    if (!gl.getShaderParameter(shader, gl.COMPILE_STATUS)) {\n      console.error(gl.getShaderInfoLog(shader));\n    }\n    return shader;\n  }\n\n  var program = gl.createProgram();\n  gl.attachShader(program, createShader(gl, gl.VERTEX_SHADER, vs));\n  gl.attachShader(program, createShader(gl, gl.FRAGMENT_SHADER, fs));\n  gl.linkProgram(program);\n  if (!gl.getProgramParameter(program, gl.LINK_STATUS)) {\n    console.error(gl.getProgramInfoLog(program));\n  }\n\n  var posLoc = gl.getAttribLocation(program, 'pos');\n  var timeLoc = gl.getUniformLocation(program, 'uTime');\n  var colorLoc = gl.getUniformLocation(program, 'uColor');\n  var speedLoc = gl.getUniformLocation(program, 'uSpeed');\n  var scaleLoc = gl.getUniformLocation(program, 'uScale');\n  var rotLoc = gl.getUniformLocation(program, 'uRotation');\n  var noiseLoc = gl.getUniformLocation(program, 'uNoiseIntensity');\n\n  var buffer = gl.createBuffer();\n  gl.bindBuffer(gl.ARRAY_BUFFER, buffer);\n  gl.bufferData(gl.ARRAY_BUFFER, new Float32Array([-1,-1, 3,-1, -1,3]), gl.STATIC_DRAW);\n\n  gl.enableVertexAttribArray(posLoc);\n  gl.vertexAttribPointer(posLoc, 2, gl.FLOAT, false, 0, 0);\n\n  var w, h;\n  function resize() {\n    // 2x downscaling for lag-free performance on all preview cards\n    w = c.width = Math.floor((c.offsetWidth || 320) / 2);\n    h = c.height = Math.floor((c.offsetHeight || 200) / 2);\n    gl.viewport(0, 0, w, h);\n  }\n  window.addEventListener('resize', resize);\n  resize();\n\n  var t = 0;\n  function draw() {\n    t += 0.00167; // matches 0.1 * delta on a 60fps frame\n    gl.useProgram(program);\n    gl.uniform1f(timeLoc, t);\n    \n    // Default uniforms: speed=5, scale=1, color=#7B7481 (123/255, 116/255, 129/255), noise=1.5, rot=0\n    gl.uniform1f(speedLoc, 5.0);\n    gl.uniform1f(scaleLoc, 1.0);\n    gl.uniform3f(colorLoc, 123/255, 116/255, 129/255);\n    gl.uniform1f(rotLoc, 0.0);\n    gl.uniform1f(noiseLoc, 1.5);\n\n    gl.drawArrays(gl.TRIANGLES, 0, 3);\n    requestAnimationFrame(draw);\n  }\n  draw();\n})();\n</script>\n"
